import { useEffect, useMemo } from 'react';
import { GrafloriaFlow } from '@grafloria/react';
import { MemoryHub } from '@grafloria/element';
import { markReady } from '../ready';

/** Offline & reconnect: two peers on one MemoryHub via collab. Anti-entropy
 *  exchanges exactly the ops each side missed and the two converge — no lost
 *  edits, no full resend. Offline edits are held in the local op log; the
 *  reconnect's sync round delivers them. */
const spec = () => ([
  { id: 'a', label: 'Alpha', position: { x: 80,  y: 90 }, size: { width: 150, height: 66 } },
  { id: 'b', label: 'Beta',  position: { x: 320, y: 90 }, size: { width: 150, height: 66 } },
]);
const edges = [{ id: 'e1', source: 'a', target: 'b' }];
const badge = { position: 'absolute', top: 8, left: 8, zIndex: 2, font: '11px ui-monospace,Menlo,monospace', background: 'rgba(37,99,235,.85)', color: '#fff', padding: '2px 8px', borderRadius: 4 } as const;

export default function OfflineAndReconnectDemo() {
  useEffect(() => markReady(), []);
  const { collabA, collabB } = useMemo(() => {
    const hub = new MemoryHub();
    return {
      collabA: { transport: hub.connect('ana'), actor: 'ana', batch: false },
      collabB: { transport: hub.connect('bo'), actor: 'bo', batch: false },
    };
  }, []);
  return (
    <div>
      <div style={{ fontSize: 12, opacity: .8, padding: '10px 24px', borderBottom: '1px solid rgba(127,127,127,.25)' }}>
        Cut the connection, edit both sides while disconnected, then reconnect — anti-entropy
        exchanges exactly the ops each side missed and the two converge.
      </div>
      <div style={{ display: 'flex', height: 'calc(100vh - 45px)' }}>
        <div style={{ flex: 1, minWidth: 0, position: 'relative', borderRight: '2px solid rgba(127,127,127,.35)' }}>
          <span style={badge}>peer A</span>
          <GrafloriaFlow defaultNodes={spec()} defaultEdges={edges} collab={collabA as never} style={{ display: 'block', height: '100%' }} />
        </div>
        <div style={{ flex: 1, minWidth: 0, position: 'relative' }}>
          <span style={badge}>peer B</span>
          <GrafloriaFlow defaultNodes={spec()} defaultEdges={structuredClone(edges)} collab={collabB as never} style={{ display: 'block', height: '100%' }} />
        </div>
      </div>
    </div>
  );
}

collab/presentation-mode.text:
import { useMemo, useRef } from 'react';
import { GrafloriaFlow } from '@grafloria/react';
import type { DiagramInstance } from '@grafloria/react';
import { InMemoryViewportChannel, presentTo, followPresenter, lockDocument } from '@grafloria/element';
import { markReady } from '../ready';

/** Presentation mode: the presenter drives the camera and every follower's
 *  viewport follows — the same world region at the same zoom, each keeping its
 *  own canvas size. The follower is read-only from the moment it mounts (the
 *  document lock drives the engine's real mode), yet its camera gestures stay
 *  live, because following is camera work, not a document edit. */
const spec = () => ([
  { id: 'a', label: 'A', position: { x: 60,  y: 80 },  size: { width: 130, height: 60 } },
  { id: 'b', label: 'B', position: { x: 320, y: 80 },  size: { width: 130, height: 60 } },
  { id: 'c', label: 'C', position: { x: 190, y: 240 }, size: { width: 130, height: 60 } },
]);
const edges = [{ id: 'e1', source: 'a', target: 'b' }, { id: 'e2', source: 'a', target: 'c' }];

export default function PresentationModeDemo() {
  const instA = useRef<DiagramInstance | null>(null);
  const instB = useRef<DiagramInstance | null>(null);
  const channel = useMemo(() => new InMemoryViewportChannel(), []);

  const wire = () => {
    const A = instA.current, B = instB.current;
    if (!A || !B) return;
    const hostA = { viewport: A.viewport, render: () => A.renderNow() };
    const hostB = { viewport: B.viewport, render: () => B.renderNow() };
    presentTo(hostA as never, channel, { presenterId: 'ana', throttleMs: 0 });
    followPresenter(hostB as never, channel, { ignorePresenterId: 'bo' });
    const engB = B.getEngine();
    if (engB) lockDocument(engB, true);
    A.fitView(60);
    markReady();
  };

  const badgeR = { position: 'absolute', top: 8, left: 8, zIndex: 2, font: '11px ui-monospace,Menlo,monospace', background: 'rgba(220,38,38,.9)', color: '#fff', padding: '2px 8px', borderRadius: 4 } as const;
  const badgeB = { ...badgeR, background: 'rgba(37,99,235,.85)' } as const;

  return (
    <div>
      <div style={{ fontSize: 12, opacity: .8, padding: '10px 24px', borderBottom: '1px solid rgba(127,127,127,.25)' }}>
        The presenter drives the camera; the follower's viewport follows — read-only from the moment it mounts.
      </div>
      <div style={{ display: 'flex', height: 'calc(100vh - 45px)' }}>
        <div style={{ flex: 1, minWidth: 0, position: 'relative', borderRight: '2px solid rgba(127,127,127,.35)' }}>
          <span style={badgeR}>presenter</span>
          <GrafloriaFlow defaultNodes={spec()} defaultEdges={edges} plugins style={{ display: 'block', height: '100%' }}
            onInit={(i) => { instA.current = i; wire(); }} />
        </div>
        <div style={{ flex: 1, minWidth: 0, position: 'relative' }}>
          <span style={badgeB}>follower (read-only)</span>
          <GrafloriaFlow defaultNodes={spec()} defaultEdges={structuredClone(edges)} style={{ display: 'block', height: '100%' }}
            onInit={(i) => { instB.current = i; wire(); }} />
        </div>
      </div>
    </div>
  );
}

whiteboard/eraser.text:
import { useRef } from 'react';
import { GrafloriaFlow } from '@grafloria/react';
import type { DiagramInstance } from '@grafloria/react';
import { registerTool, createEraserTool, StrokeModel } from '@grafloria/element';
import { markReady } from '../ready';
import { whiteboardHost } from './whiteboard-host';

/** Eraser: wipe over ink to remove it. Whole-stroke delete; a sweep across
 *  several strokes is one undo step. Three parallel strokes are seeded and the
 *  eraser tool is live against the canvas. */
const ink = (id: string, y: number) =>
  new StrokeModel([{ x: 100, y }, { x: 300, y }, { x: 500, y }], { color: '#1f2933', width: 4 }, { id });

export default function EraserDemo() {
  const hostRef = useRef<HTMLDivElement | null>(null);

  const onInit = (instance: DiagramInstance) => {
    const model = instance.getModel() as any;
    if (model) {
      model.addStroke(ink('top', 120));
      model.addStroke(ink('mid', 240));
      model.addStroke(ink('bot', 360));
      registerTool(createEraserTool(whiteboardHost(instance, hostRef.current!), { radius: 10 }));
      instance.renderNow();
    }
    markReady();
  };

  return (
    <div ref={hostRef} style={{ display: 'block', height: '100vh' }}>
      <GrafloriaFlow defaultNodes={[]} defaultEdges={[]} style={{ display: 'block', height: '100%' }} onInit={onInit} />
    </div>
  );
}

