import { useRef } from 'react';
import { GrafloriaFlow } from '@grafloria/react';
import type { DiagramInstance } from '@grafloria/react';
import { QualityGovernor, PerfHud, EMPTY_SNAPSHOT } from '@grafloria/element';
import { markReady } from '../ready';

/** Perf HUD & quality governor: an adaptive governor that steps the render tier
 *  DOWN under load and restores it when the budget recovers, and a HUD that
 *  reports it — fed live scene numbers off the mounted canvas. */
const nodes = Array.from({ length: 24 }, (_, i) => ({
  id: 'n' + i, label: 'N' + i,
  position: { x: 40 + (i % 6) * 150, y: 40 + Math.floor(i / 6) * 110 },
  size: { width: 120, height: 60 },
}));
const edges = Array.from({ length: 20 }, (_, i) => ({ id: 'e' + i, source: 'n' + i, target: 'n' + (i + 1) }));

export default function PerfHudDemo() {
  const hudRef = useRef<HTMLDivElement | null>(null);

  const onInit = (instance: DiagramInstance) => {
    const model = instance.getModel() as any;
    const gov = new QualityGovernor();
    const hud = new PerfHud(hudRef.current!);
    hud.show();
    if (model) {
      const hostEl = hudRef.current!.parentElement as HTMLElement;
      hud.update({
        ...EMPTY_SNAPSHOT,
        nodes: model.getNodes().length,
        visibleNodes: hostEl.querySelectorAll('[data-node-id]').length,
        links: model.getLinks().length,
        visibleLinks: hostEl.querySelectorAll('[data-link-id]').length,
        tier: 'high',
        governor: gov.getState(),
      } as never);
    }
    markReady();
  };

  return (
    <div>
      <div style={{ fontSize: 12, opacity: .8, padding: '10px 24px', borderBottom: '1px solid rgba(127,127,127,.25)' }}>
        An adaptive quality governor and a HUD that reports it — measured live off the mounted scene.
      </div>
      <div style={{ height: 'calc(100vh - 45px)', position: 'relative' }}>
        <GrafloriaFlow defaultNodes={nodes} defaultEdges={edges} style={{ display: 'block', height: '100%' }} onInit={onInit} />
        <div ref={hudRef} style={{ position: 'absolute', top: 12, right: 12, width: 280, zIndex: 5 }} />
      </div>
    </div>
  );
}

misc/server-side-export.text:
import { useEffect, useRef, useState } from 'react';
import { renderStatic } from '@grafloria/element';
import { markReady } from '../ready';

/** Server-side export: a headless, deterministic render — pure spec → SVG with
 *  ZERO DOM (no createDiagram, no mounting). Two independent renders of the same
 *  spec are byte-identical, which is what makes it safe to run on a server,
 *  cache, and diff. The <svg> string is pasted straight into the page. */
const SPEC = {
  nodes: [
    { id: 'a', label: 'Extract', position: { x: 40,  y: 40 }, size: { width: 150, height: 66 } },
    { id: 'b', label: 'Load',    position: { x: 260, y: 40 }, size: { width: 150, height: 66 } },
    { id: 'c', label: 'Model',   position: { x: 150, y: 170 }, size: { width: 150, height: 66 } },
  ],
  edges: [{ id: 'e1', source: 'a', target: 'b' }, { id: 'e2', source: 'a', target: 'c' }],
};
/** FNV-1a — a byte-level fingerprint, so "byte-identical" has a number behind it. */
const fnv = (s: string) => {
  let h = 0x811c9dc5;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 0x01000193); }
  return (h >>> 0).toString(16);
};

export default function ServerSideExportDemo() {
  const preview = useRef<HTMLDivElement | null>(null);
  const [hash, setHash] = useState('');

  useEffect(() => {
    const r = renderStatic({ nodes: SPEC.nodes, edges: SPEC.edges, width: 520, height: 300, standalone: true } as never) as any;
    if (preview.current) preview.current.innerHTML = `<style>${r.css}</style>${r.svg}`;
    const inlined = String(r.svg).replace(/^(<svg[^>]*>)/, `$1<style>${r.css}</style>`);
    setHash(`standalone artifact fingerprint: ${fnv(inlined)}`);
    markReady();
  }, []);

  return (
    <div>
      <div style={{ fontSize: 12, opacity: .8, padding: '10px 24px', borderBottom: '1px solid rgba(127,127,127,.25)' }}>
        A headless, deterministic export — pure spec → SVG with zero DOM. Independent renders are byte-identical.
      </div>
      <div style={{ padding: '16px 24px', overflow: 'auto' }}>
        <div ref={preview} style={{ border: '1px solid rgba(127,127,127,.3)', borderRadius: 8, display: 'inline-block' }} />
        <div style={{ font: '12px ui-monospace,Menlo,monospace', marginTop: 12, opacity: .8 }}>{hash}</div>
      </div>
    </div>
  );
}

